  async function getActiveWorldbookEntries() {
    const results = [];
    const checked = new Set();
    try {
      const ctx = ST && ST.getContext ? ST.getContext() : null;
      if (!ctx) return results;

      const charId = ctx.characterId;
      if (charId >= 0 && ctx.characters && ctx.characters[charId]) {
        const char = ctx.characters[charId];
        const charWorldName = char?.data?.extensions?.world || char?.data?.world;
        if (charWorldName && !checked.has(charWorldName)) {
          checked.add(charWorldName);
          try {
            const entries = await TH.getLorebookEntries(charWorldName);
            if (Array.isArray(entries)) entries.forEach(e => results.push({
              label: `[${charWorldName}] ${e.comment || e.name || '(无标题)'}`,
              content: e.content || '', wbName: charWorldName, uid: e.uid,
            }));
          } catch(e2) { warn('角色世界书加载失败:', e2); }
        }
        const cb = char?.data?.character_book;
        if (cb && Array.isArray(cb.entries)) {
          cb.entries.forEach(e => results.push({
            label: `[角色内嵌] ${e.comment || e.name || '(无标题)'}`,
            content: e.content || '', wbName: '__inline__', uid: e.id,
          }));
        }
      }

      const chatMeta = ctx.chatMetadata || {};
      const metaWorld = chatMeta.world_info || chatMeta.worldInfo || chatMeta.world;
      if (metaWorld) {
        const bookList = Array.isArray(metaWorld) ? metaWorld : [metaWorld];
        for (const bName of bookList) {
          if (bName && !checked.has(bName)) {
            checked.add(bName);
            try {
              const entries = await TH.getLorebookEntries(bName);
              if (Array.isArray(entries)) entries.forEach(e => results.push({
                label: `[${bName}] ${e.comment || e.name || '(无标题)'}`,
                content: e.content || '', wbName: bName, uid: e.uid,
              }));
            } catch(e2) {}
          }
        }
      }

      const gwi = ctx.worldInfo || ctx.globalWorldInfo;
      if (gwi && typeof gwi === 'object') {
        for (const bName of Object.keys(gwi)) {
          if (bName && !checked.has(bName)) {
            checked.add(bName);
            try {
              const entries = await TH.getLorebookEntries(bName);
              if (Array.isArray(entries)) entries.forEach(e => results.push({
                label: `[全局:${bName}] ${e.comment || e.name || '(无标题)'}`,
                content: e.content || '', wbName: bName, uid: e.uid,
              }));
            } catch(e2) {}
          }
        }
      }
    } catch(e) { err('getActiveWorldbookEntries:', e); }
    return results;
  }

