  async function callAI(prompt) {
    if (apiConfig.useMain) {
      if (TH && typeof TH.triggerSlash === 'function') {
        await TH.triggerSlash(`/send ${prompt}`);
        await TH.triggerSlash('/trigger');
        return await waitForAIResponse();
      }
      throw new Error('主API的 triggerSlash 在当前环境不可用，请切换为自定义API');
    }
    if (!apiConfig.url || !apiConfig.model) throw new Error('请先配置自定义API');
    let url = apiConfig.url.trim();
    if (!url.endsWith('/')) url += '/';
    if (!url.includes('v1/')) url += 'v1/';
    url += 'chat/completions';
    const headers = { 'Content-Type': 'application/json' };
    if (apiConfig.apiKey) headers['Authorization'] = `Bearer ${apiConfig.apiKey}`;
    const res = await fetch(url, {
      method: 'POST', headers,
      body: JSON.stringify({ model: apiConfig.model, messages: [{ role:'user', content: prompt }], temperature: 1, max_tokens: 4096 }),
    });
    if (!res.ok) { const t = await res.text(); throw new Error(`API错误 ${res.status}: ${t.slice(0,200)}`); }
    const data = await res.json();
    if (data.choices?.[0]?.message?.content) return data.choices[0].message.content.trim();
    throw new Error('API响应格式异常');
  }

  async function waitForAIResponse(timeout = 90000) {
    return new Promise((resolve, reject) => {
      const timer = setTimeout(() => reject(new Error('等待AI响应超时')), timeout);
      const pw = (window !== window.parent) ? window.parent : window;
      const evOnce = pw.eventOnce || (typeof eventOnce !== 'undefined' ? eventOnce : null);
      const evts   = pw.tavern_events || (typeof tavern_events !== 'undefined' ? tavern_events : null);
      if (!evOnce || !evts) {
        clearTimeout(timer);
        reject(new Error('eventOnce/tavern_events 不可用，请使用自定义API'));
        return;
      }
      evOnce(evts.MESSAGE_RECEIVED, async (msgId) => {
        clearTimeout(timer);
        try {
          const msgs = TH.getChatMessages ? await TH.getChatMessages(msgId) : [];
          resolve(msgs && msgs.length ? msgs[0].message || '' : '');
        } catch(e) { reject(e); }
      });
    });
  }

  // ─────────────────────────────────────────
  // 解析响应
  // ─────────────────────────────────────────
  function parseResponse(text) {
    const infoM    = text.match(/<dungeon_info>([\s\S]*?)<\/dungeon_info>/);
    const dungeonM = text.match(/<dungeon>([\s\S]*?)<\/dungeon>/);
    return { info: infoM ? infoM[1].trim() : '', full: dungeonM ? dungeonM[1].trim() : text, raw: text };
  }
  function parseDungeonInfo(infoText) {
    const get = (key) => { const m = infoText.match(new RegExp(`${key}：([^\\n]+)`)); return m ? m[1].trim() : ''; };
    return { name: get('副本名称'), themes: get('副本主题'), rating: get('评级'), players: get('人数'), opening: get('开场') };
  }

  // ─────────────────────────────────────────
  // 构建 Prompt
  // ─────────────────────────────────────────
  async function buildPrompt(cfg) {
    const $p = getPopup();

    const themesStr  = (cfg.themes.includes('全选')  || !cfg.themes.length)  ? '随机' : cfg.themes.join('、');
    const ratingsStr = (cfg.ratings.includes('全选') || !cfg.ratings.length) ? '随机' : cfg.ratings.join('/');
    const playersStr = cfg.players.trim() || '随机';
    const specialStr = cfg.special || '无';

    const configBlock =
`以下是副本配置信息：
副本名称：${cfg.name || '（随机）'}
副本主题：${themesStr}
评级：${ratingsStr}
人数：${playersStr}
竞争模式：${cfg.mode}
特殊要求：${specialStr}
队友姓名：${cfg.teammates}
语言：${cfg.lang}
读取设定：${cfg.readContext}`;

    const isFusion = cfg.readContext === '是';

    let wbText = '无';
    if (isFusion && $p) {
      const sel = [];
      $p.find('#dg-lorebook-list .dg-tag-btn.active').each(function () {
        const e = $j(this).data('entry');
        if (e && e.content) sel.push(`[${e.label}]\n${e.content}`);
      });
      if (sel.length) wbText = sel.join('\n\n');
    }

    // 读取 persona：优先使用自定义编辑文本，其次从 ST 上下文读取
    let personaText = '无', charDescText = '无';
    if (isFusion) {
      try {
        const ctx = ST && ST.getContext ? ST.getContext() : null;
        if ($p) {
          if ($p.find('#chk-persona').is(':checked')) {
            if (customPersonaText && customPersonaText.trim()) {
              // [Change 2] 自定义文本优先
              personaText = customPersonaText.trim();
            } else if (ctx) {
              personaText = ctx.personaDescription || ctx.persona || ctx.user_desc || '无';
            }
          }
          if ($p.find('#chk-char-desc').is(':checked') && ctx) {
            const char = ctx.characters && ctx.characterId >= 0 ? ctx.characters[ctx.characterId] : null;
            const charData = char?.data || char || {};
            charDescText = ctx.description || charData.description || '无';
          }
        }
      } catch(e) { warn('读取ST上下文失败:', e); }
    }

    log(`buildPrompt: isFusion=${isFusion}, wbText长度=${wbText.length}, persona=${personaText!=='无'}, charDesc=${charDescText!=='无'}, customPersona=${!!customPersonaText.trim()}`);

    // [Change 1] 聊天注入仅在融合模式下生效
    let chatBlock = '';
    if (cfg.injectChat && isFusion) {
      const lastMsg = await getLastChatMessage();
      if (lastMsg && lastMsg.trim()) {
        // [Change 3] 用【】包裹
        chatBlock = `\n【以下为最新剧情内容，请根据剧情内容自动提取副本相关信息，生成匹配的副本】\n${lastMsg.trim()}`;
        log('chatBlock injected, length:', lastMsg.length);
      } else {
        chatBlock = '\n（注入聊天记录：当前聊天为空或未获取到内容）';
        warn('chatBlock: no message found');
      }
    }

    // [Change 3] 用【】包裹各 section header
    const contextSection = isFusion
      ? `\n【以下是世界观设定】\n${wbText}\n【以下是{{user}}的基本信息】\n${personaText}\n【以下是角色信息】\n${charDescText}`
      : '';

    const module0Block = `${configBlock}${contextSection}${chatBlock}`;

    if (currentPrompt.includes('{{MODULE_0_BLOCK}}')) {
      return currentPrompt.replace('{{MODULE_0_BLOCK}}', module0Block);
    }
    return currentPrompt
      .replace('{{副本名称}}',  cfg.name || '（随机）')
      .replace('{{副本主题}}',  themesStr)
      .replace('{{评级}}',      ratingsStr)
      .replace('{{人数}}',      playersStr)
      .replace('{{竞争模式}}',  cfg.mode)
      .replace('{{特殊要求}}',  specialStr)
      .replace('{{队友姓名}}',  cfg.teammates)
      .replace('{{语言}}',      cfg.lang)
      .replace('{{读取设定}}',  cfg.readContext)
      .replace('{{附加设定}}',  isFusion ? `\n${wbText}\n${personaText}\n${charDescText}` : '')
      .replace('{{聊天记录}}',  chatBlock);
  }

  // ─────────────────────────────────────────
  // 读取 UI 配置
  // ─────────────────────────────────────────
  function getConfig() {
    const $p = getPopup(); if (!$p) return null;

    // 将 data-theme/data-rating 值扩展为「名称（解释）」格式（供 prompt 使用）
    // 自定义选项有 desc 则附加，内置选项直接用名称
    const expandName = (name, arr) => {
      const found = arr.find(x => (typeof x === 'string' ? x : x.name) === name);
      if (found && typeof found === 'object' && found.desc) return `${name}（${found.desc}）`;
      return name;
    };

    const themes = [], ratings = [];
    $p.find('#dg-themes-container .dg-tag-btn.active').each(function () {
      themes.push(expandName($j(this).data('theme'), customThemes));
    });
    $p.find('#dg-ratings-container .dg-rating-btn.active').each(function () {
      ratings.push(expandName($j(this).data('rating'), customRatings));
    });

    const getOpt = (gid) => $p.find(`#${gid} .dg-opt-btn.active`).data('val') || '';
    return {
      name:        $p.find('#dg-name').val().trim(),
      players:     $p.find('#dg-players').val().trim(),
      themes:      themes.length ? themes : ['随机'],
      ratings:     ratings.length ? ratings : ['随机'],
      mode:        getOpt('dg-mode-group'),
      teammates:   getOpt('dg-teammate-group'),
      lang:        getOpt('dg-lang-group'),
      readContext: getOpt('dg-context-group'),
      injectChat:  $p.find('#dg-inject-chat').is(':checked'),
      special:     $p.find('#dg-special').val().trim(),
      contextText: ($p.find('#dg-context-text').val() || '').trim(),
    };
  }

  // ─────────────────────────────────────────
  // 菜单项
  // ─────────────────────────────────────────
  function addMenuItem() {
    const docs = [];
    try { if (window.parent && window.parent !== window) docs.push(window.parent.document); } catch(e) {}
    docs.push(document);

    for (const pd of docs) {
      if (!pd || !$j) continue;
      if ($j(`#${MENU_ID}`, pd).length) return;

      let menu = null;
      for (const sel of MENU_SELECTORS) {
        const found = $j(sel, pd);
        if (found.length) { menu = found; log(`菜单容器命中: ${sel}`); break; }
      }

      if (menu) {
        _appendMenuItem(menu, pd);
        return;
      }
    }

    if (typeof addMenuItem._retries === 'undefined') addMenuItem._retries = 0;
    addMenuItem._retries++;

    if (addMenuItem._retries < 30) {
      const delay = addMenuItem._retries < 5 ? 1000 : addMenuItem._retries < 15 ? 2000 : 3000;
      log(`菜单容器未找到，第 ${addMenuItem._retries} 次重试，${delay}ms 后...`);
      setTimeout(addMenuItem, delay);
    } else {
      warn('菜单容器始终未找到，改用浮动按钮兜底');
      _appendFloatingButton();
    }
  }

  function _appendMenuItem(menu, pd) {
    if ($j(`#${MENU_ID}`, pd).length) return;
    const $wrap = $j('<div class="extension_container interactable" tabindex="0"></div>');
    const $item = $j(`
      <div class="list-group-item flex-container flexGap5 interactable" id="${MENU_ID}" title="无限流副本生成器">
        <div class="fa-fw fa-solid fa-dungeon extensionsMenuExtensionButton"></div>
        <span>副本生成器</span>
      </div>`);
    $item.on('click', async (e) => {
      e.stopPropagation();
      try {
        const btn = $j('#extensionsMenuButton', pd);
        if (btn.length && menu.is(':visible')) { btn.trigger('click'); await new Promise(r=>setTimeout(r,150)); }
      } catch(e2) {}
      openPopup();
    });
    $wrap.append($item);
    menu.append($wrap);
    log('菜单项已添加到', menu.attr('id') || menu.attr('class'));
  }

  function _appendFloatingButton() {
    const pd = document;
    if ($j(`#${MENU_ID}-float`, pd).length) return;
    const $btn = $j(`
      <button id="${MENU_ID}-float"
        title="无限流副本生成器"
        style="position:fixed;bottom:20px;right:20px;z-index:99990;
               width:48px;height:48px;border-radius:50%;
               background:#8b0000;border:2px solid #cc2200;color:#fff;
               font-size:20px;cursor:pointer;box-shadow:0 2px 12px rgba(139,0,0,.5);
               display:flex;align-items:center;justify-content:center;">
        ⚔
      </button>`);
    $btn.on('click', openPopup);
    $j(pd.body).append($btn);
    log('浮动兜底按钮已添加');
  }

  // ─────────────────────────────────────────
  // 自定义标签（主题 / 评级）
  // ─────────────────────────────────────────
  function saveCustomThemes()  { try { localStorage.setItem(STORAGE_KEY_CUSTOM_THEMES,  JSON.stringify(customThemes));  } catch(e) {} }
  function saveCustomRatings() { try { localStorage.setItem(STORAGE_KEY_CUSTOM_RATINGS, JSON.stringify(customRatings)); } catch(e) {} }

  function buildCustomTagEl(item, type) {
    // item = { name, desc }  desc 用于 prompt，按钮只显示 name
    const $p   = getPopup();
    const name = typeof item === 'string' ? item : item.name;
    const attr  = type === 'theme' ? 'data-theme' : 'data-rating';
    const extra = type === 'rating' ? ' dg-rating-btn' : '';
    const $tag  = $j(
      `<button class="dg-tag-btn dg-tag-custom${extra}" ${attr}="${esc(name)}">` +
      `${esc(name)}<span class="dg-tag-del" title="删除此自定义选项">✕</span>` +
      `</button>`
    );

    $tag.on('click', function(e) {
      if ($j(e.target).hasClass('dg-tag-del')) { e.stopPropagation(); return; }
      const container = type === 'theme' ? '#dg-themes-container' : '#dg-ratings-container';
      $p.find(`${container} .dg-tag-all`).removeClass('active');
      $tag.toggleClass('active');
    });

    $tag.find('.dg-tag-del').on('click', function(e) {
      e.stopPropagation();
      if (type === 'theme') {
        customThemes = customThemes.filter(x => (typeof x === 'string' ? x : x.name) !== name);
        saveCustomThemes();
        renderCustomTags('theme');
      } else {
        customRatings = customRatings.filter(x => (typeof x === 'string' ? x : x.name) !== name);
        saveCustomRatings();
        renderCustomTags('rating');
      }
      toast('info', `已删除自定义选项「${name}」`);
    });

    return $tag;
  }

  function renderCustomTags(type) {
    const $p = getPopup(); if (!$p) return;
    const containerId = type === 'theme' ? '#dg-themes-container' : '#dg-ratings-container';
    const addBtnId    = type === 'theme' ? '#dg-add-theme-btn'    : '#dg-add-rating-btn';
    const $container  = $p.find(containerId);
    $container.find('.dg-tag-custom').remove();
    const list    = type === 'theme' ? customThemes : customRatings;
    const $addBtn = $container.find(addBtnId);
    list.forEach(item => {
      const $tag = buildCustomTagEl(item, type);
      if ($addBtn.length) $addBtn.before($tag);
      else $container.append($tag);
    });
  }

  function openAddTagModal(type) {
    const isTheme = type === 'theme';
    const label   = isTheme ? '主题' : '评级';
    const placeholder = isTheme
      ? { name: '例：蒸汽朋克', desc: '例：工业机械与蒸汽动力的异变世界' }
      : { name: '例：XS',       desc: '例：极限挑战，通关率接近0%' };

    showModal({
      title: `添加自定义${label}`,
      body: `
        <div class="dg-field" style="margin-bottom:12px;">
          <label>${label}名称 <span style="color:var(--accent2);">*</span></label>
          <input type="text" id="dg-add-tag-name" placeholder="${placeholder.name}" style="margin-top:4px;">
        </div>
        <div class="dg-field">
          <label>说明（选填）</label>
          <div class="dg-hint" style="margin-bottom:5px;">将显示在按钮的括号内，不填则只显示名称。</div>
          <input type="text" id="dg-add-tag-desc" placeholder="${placeholder.desc}" style="margin-top:2px;">
        </div>`,
      footer: `
        <button class="dg-btn dg-btn-primary" style="flex:1;" id="dg-add-tag-confirm">添加</button>
        <button class="dg-btn" id="dg-add-tag-cancel" style="padding:8px 16px;">取消</button>`,
      onAfterRender: () => {
        const $p = getPopup();
        $p.find('#dg-add-tag-name').focus();

        const doAdd = () => {
          const name = $p.find('#dg-add-tag-name').val().trim();
          const desc = $p.find('#dg-add-tag-desc').val().trim();
          if (!name) { toast('warning', '请输入名称'); return; }

          const exists = (arr) => arr.some(x => (typeof x === 'string' ? x : x.name) === name);

          if (isTheme) {
            if (THEMES.includes(name) || exists(customThemes)) { toast('warning', `「${name}」已存在`); return; }
            customThemes.push({ name, desc });
            saveCustomThemes();
            renderCustomTags('theme');
            // 自动选中新标签
            const $p2 = getPopup();
            $p2.find('#dg-themes-container .dg-tag-all').removeClass('active');
            $p2.find(`#dg-themes-container [data-theme="${esc(name)}"]`).addClass('active');
          } else {
            if (RATINGS.includes(name) || exists(customRatings)) { toast('warning', `「${name}」已存在`); return; }
            customRatings.push({ name, desc });
            saveCustomRatings();
            renderCustomTags('rating');
            const $p2 = getPopup();
            $p2.find('#dg-ratings-container .dg-tag-all').removeClass('active');
            $p2.find(`#dg-ratings-container [data-rating="${esc(name)}"]`).addClass('active');
          }
          toast('success', `已添加自定义${label}「${name}」${desc ? `（${desc}）` : ''}`);
          closeModal();
        };

        $p.find('#dg-add-tag-confirm').on('click', doAdd);
        $p.find('#dg-add-tag-name, #dg-add-tag-desc').on('keydown', e => {
          if (e.key === 'Enter') { e.preventDefault(); doAdd(); }
        });
        $p.find('#dg-add-tag-cancel').on('click', closeModal);
      },
    });
  }

