  // ─────────────────────────────────────────
  // 弹窗管理
  // ─────────────────────────────────────────
  async function openPopup() {
    if (!apisReady) loadApis();
    loadSettings();

    if (ST && ST.callGenericPopup && ST.POPUP_TYPE) {
      ST.callGenericPopup(buildPopupHTML(), ST.POPUP_TYPE.DISPLAY, '副本生成器', {
        wide: true, large: true, allowVerticalScrolling: true, buttons: [],
        callback: () => { $popup = null; },
      });
    } else {
      _openNativeDialog();
    }

    await new Promise(r => setTimeout(r, 400));

    let found = null;
    $j('dialog[open]').each(function () {
      const f = $j(this).find(`#${POPUP_ID}`);
      if (f.length) { found = f; return false; }
    });
    if (!found) {
      const f = $j(`#${POPUP_ID}`);
      if (f.length) found = f;
    }
    if (!found) { err('Cannot find popup DOM'); return; }
    $popup = found;

    const bgColor   = currentTheme === 'dark' ? '#0c0c0c' : '#f5f5f5';
    const textColor = currentTheme === 'dark' ? '#d4c5b0' : '#1e293b';
    $popup.closest('dialog, .popup_content, .dialogue_popup, .wide_dialogue_popup')
          .css({ background: bgColor, color: textColor });
    $popup.parent().css({ background: bgColor });

    if (!apisReady) {
      $popup.find('#dg-api-warn-banner').show();
      $popup.find('#dg-api-custom').prop('checked', true);
      $popup.find('#dg-custom-api-fields').css({ opacity:'1', pointerEvents:'auto' });
    }

    bindEvents();
    updateApiStatus();
    renderPresets();
  }

  function _openNativeDialog() {
    $j('#dg-native-dialog').remove();
    const $dlg = $j(`<dialog id="dg-native-dialog" style="
      padding:0;border:none;background:transparent;max-width:900px;width:95vw;
      max-height:92vh;overflow-y:auto;z-index:99990;
    ">${buildPopupHTML()}<div style="text-align:center;padding:12px;">
      <button id="dg-native-close" style="background:#5c0000;border:1px solid #8b0000;color:#fff;
        padding:8px 24px;cursor:pointer;font-size:13px;">关闭</button>
    </div></dialog>`);
    $j(document.body).append($dlg);
    $dlg[0].showModal();
    $dlg.find('#dg-native-close').on('click', () => { $dlg[0].close(); $dlg.remove(); $popup = null; });
  }

  function getPopup() { return $popup; }

  // ─────────────────────────────────────────
  // 事件绑定
  // ─────────────────────────────────────────
  function bindEvents() {
    const $p = getPopup(); if (!$p) return;

    $p.find('#dg-nav-gen').on('click', () => switchView('generator'));
    $p.find('#dg-nav-set').on('click', () => switchView('settings'));

    $p.find('#dg-themes-container .dg-tag-btn').on('click', function () {
      const val = $j(this).data('theme');
      if (val === '全选') { $p.find('#dg-themes-container .dg-tag-btn').removeClass('active'); $j(this).addClass('active'); }
      else { $p.find('#dg-themes-container .dg-tag-all').removeClass('active'); $j(this).toggleClass('active'); }
    });

    $p.find('#dg-ratings-container .dg-rating-btn').on('click', function () {
      const val = $j(this).data('rating');
      if (val === '全选') { $p.find('#dg-ratings-container .dg-rating-btn').removeClass('active'); $j(this).addClass('active'); }
      else { $p.find('#dg-ratings-container .dg-tag-all').removeClass('active'); $j(this).toggleClass('active'); }
    });

    // 自定义主题 / 评级
    renderCustomTags('theme');
    renderCustomTags('rating');
    $p.find('#dg-add-theme-btn').on('click', () => openAddTagModal('theme'));
