    const cfg = getConfig();
    if (!cfg) return;
    const $p = getPopup();
    if ($p) $p.find('#dg-generate-btn').prop('disabled', true).text('构建Prompt...');
    try {
      const builtPrompt = await buildPrompt(cfg);
      if ($p) $p.find('#dg-generate-btn').prop('disabled', false).text('生成世界 · INITIALIZE WORLD');
      showPreviewModal(cfg, builtPrompt);
    } catch(e) {
      if ($p) $p.find('#dg-generate-btn').prop('disabled', false).text('生成世界 · INITIALIZE WORLD');
      toast('error', `构建提示词失败: ${e.message}`);
    }
  }

