  // ─────────────────────────────────────────
  // API 操作
  // ─────────────────────────────────────────
  function updateApiStatus() {
    const $p = getPopup(); if (!$p) return;
    const $s = $p.find('#dg-api-status');
    if (apiConfig.useMain) $s.text('状态: 使用酒馆主API');
    else if (apiConfig.url && apiConfig.model) $s.html(`URL: ${esc(apiConfig.url)}<br>模型: ${esc(apiConfig.model)}`);
    else $s.text(apiConfig.url ? '已配置URL，请加载并选择模型' : '状态: 未配置自定义API');
  }

  async function loadModels() {
    const $p = getPopup(); if (!$p) return;
    const url = $p.find('#dg-api-url').val().trim();
    const key = $p.find('#dg-api-key').val();
    if (!url) { toast('warning','请输入API基础URL'); return; }
    let mu = url.endsWith('/') ? url : url+'/';
    if (!mu.includes('v1/')) mu += 'v1/';
    mu += 'models';
    $p.find('#dg-api-status').text('正在加载模型列表...');
    try {
      const h = { 'Content-Type':'application/json' };
      if (key) h['Authorization'] = `Bearer ${key}`;
      const res = await fetch(mu, { method:'GET', headers: h });
      if (!res.ok) throw new Error(`${res.status} ${res.statusText}`);
      const data = await res.json();
      const $sel = $p.find('#dg-api-model');
      $sel.empty();
      let models = [];
      if (data.data && Array.isArray(data.data)) models = data.data.map(m=>m.id).filter(Boolean);
      else if (Array.isArray(data)) models = data.map(m=>typeof m==='string'?m:m.id).filter(Boolean);
      if (!models.length) { $sel.append('<option value="">未发现模型</option>'); toast('warning','未能解析模型列表'); return; }
      models.forEach(m => $sel.append($j('<option>').val(m).text(m)));
      if (apiConfig.model && models.includes(apiConfig.model)) $sel.val(apiConfig.model);
      toast('success', `加载了 ${models.length} 个模型`);
      $p.find('#dg-api-status').text(`已加载 ${models.length} 个模型`);
    } catch(e) { err('loadModels:', e); toast('error', `加载失败: ${e.message}`); }
  }

  function saveApiConfig() {
    const $p = getPopup(); if (!$p) return;
    apiConfig = { useMain: $p.find('#dg-api-main').is(':checked'), url: $p.find('#dg-api-url').val().trim(), apiKey: $p.find('#dg-api-key').val(), model: $p.find('#dg-api-model').val() };
    saveSettings(); updateApiStatus(); toast('success','API配置已保存');
  }
  function clearApiConfig() {
    apiConfig = { useMain:true, url:'', apiKey:'', model:'' };
    const $p = getPopup();
    if ($p) {
      $p.find('#dg-api-main').prop('checked',true);
      $p.find('#dg-api-url').val(''); $p.find('#dg-api-key').val('');
      $p.find('#dg-api-model').empty().append('<option value="">请先加载模型列表</option>');
      $p.find('#dg-custom-api-fields').css({ opacity:'.4', pointerEvents:'none' });
    }
    saveSettings(); updateApiStatus(); toast('info','API配置已清除');
  }

  // ─────────────────────────────────────────
  // 预设管理
  // ─────────────────────────────────────────
  function saveCurrentPreset() {
    const $p = getPopup(); if (!$p) return;
    const name = $p.find('#dg-preset-name').val().trim();
    if (!name) { toast('warning','请输入预设名称'); return; }
    const cfg = getConfig(); if (!cfg) return;
    savedPresets = savedPresets.filter(p=>p.name!==name);
    savedPresets.unshift({ name, cfg, apiConfig:{...apiConfig}, savedAt:Date.now() });
    try { localStorage.setItem(STORAGE_KEY_PRESETS, JSON.stringify(savedPresets)); } catch(e) {}
    $p.find('#dg-preset-name').val('');
    renderPresets(); toast('success', `预设 "${name}" 已保存`);
  }

  function renderPresets() {
    const $p = getPopup(); if (!$p) return;
    const $list = $p.find('#dg-presets-list');
    $list.empty();
    if (!savedPresets.length) { $list.append('<div class="dg-hint" style="padding:8px 0;">暂无保存的预设</div>'); return; }
    savedPresets.forEach((pr, idx) => {
      const $item = $j(`<div class="dg-preset-item"><span style="color:var(--text);">${esc(pr.name)}</span><div style="display:flex;gap:6px;"><button class="dg-btn dg-btn-sm dg-load-preset" data-idx="${idx}">载入</button><button class="dg-btn dg-btn-sm dg-btn-danger dg-del-preset" data-idx="${idx}">删</button></div></div>`);
      $list.append($item);
    });
    $list.find('.dg-load-preset').on('click', function () { loadPresetCfg(savedPresets[parseInt($j(this).data('idx'))]); });
    $list.find('.dg-del-preset').on('click', function () {
      savedPresets.splice(parseInt($j(this).data('idx')), 1);
      try { localStorage.setItem(STORAGE_KEY_PRESETS, JSON.stringify(savedPresets)); } catch(e) {}
      renderPresets(); toast('info','预设已删除');
    });
  }

  function loadPresetCfg(pr) {
    const $p = getPopup(); if (!$p || !pr.cfg) return;
    const cfg = pr.cfg;
    switchView('generator');
    $p.find('#dg-name').val(cfg.name||'');
    $p.find('#dg-players').val(cfg.players||'');
    $p.find('#dg-special').val(cfg.special||'');
    $p.find('#dg-themes-container .dg-tag-btn').removeClass('active');
    (cfg.themes||[]).forEach(t => $p.find(`#dg-themes-container .dg-tag-btn[data-theme="${t}"]`).addClass('active'));
    $p.find('#dg-ratings-container .dg-rating-btn').removeClass('active');
    (cfg.ratings||[]).forEach(r => $p.find(`#dg-ratings-container .dg-rating-btn[data-rating="${r}"]`).addClass('active'));
    const so = (gid,val) => { $p.find(`#${gid} .dg-opt-btn`).removeClass('active'); $p.find(`#${gid} .dg-opt-btn[data-val="${val}"]`).addClass('active'); };
    so('dg-mode-group',     cfg.mode);
    so('dg-teammate-group', cfg.teammates);
    so('dg-lang-group',     cfg.lang);
    so('dg-context-group',  cfg.readContext);
    $p.find('#dg-context-extra').toggle(cfg.readContext==='是');
    if (cfg.injectChat !== undefined) $p.find('#dg-inject-chat').prop('checked', cfg.injectChat);
    if (pr.apiConfig) {
      apiConfig = { ...pr.apiConfig };
      $p.find('#dg-api-url').val(apiConfig.url||''); $p.find('#dg-api-key').val(apiConfig.apiKey||'');
      const isC = !apiConfig.useMain;
      $p.find(isC ? '#dg-api-custom' : '#dg-api-main').prop('checked', true);
      $p.find('#dg-custom-api-fields').css({ opacity: isC?'1':'.4', pointerEvents: isC?'auto':'none' });
      updateApiStatus();
    }
    toast('success', `预设 "${pr.name}" 已载入`);
  }

  // ─────────────────────────────────────────
  // 世界书条目加载
  // ─────────────────────────────────────────
  async function loadLorebookEntries() {
    const $p = getPopup(); if (!$p) return;
    const $list = $p.find('#dg-lorebook-list');
    $list.html('<span class="dg-hint" style="padding:8px;">正在读取当前挂载的条目...</span>');
    try {
      const entries = await getActiveWorldbookEntries();
      $list.empty();
      if (!entries.length) { $list.html('<span class="dg-hint" style="padding:8px;">当前未发现挂载的世界书条目</span>'); return; }
      entries.forEach(entry => {
        const $tag = $j(`<button class="dg-tag-btn" title="${esc((entry.content||'').slice(0,120))}">${esc(entry.label)}</button>`);
        $tag.on('click', function () { $j(this).toggleClass('active'); });
        $tag.data('entry', entry);
        $list.append($tag);
      });
      toast('success', `已载入 ${entries.length} 个挂载条目`);
    } catch(e) {
      err('loadLorebookEntries:', e);
      $list.html('<span class="dg-hint" style="padding:8px;color:var(--accent2);">加载失败</span>');
    }
  }

  // ─────────────────────────────────────────
  // 初始化
  // ─────────────────────────────────────────
  let initAttempts = 0;
  async function init() {
    initAttempts++;
    log(`Init attempt ${initAttempts}`);

    if (loadApis()) {
      log('All core APIs OK, starting...');
      loadSettings();
      addMenuItem();
    } else if (initAttempts < 25) {
      const delay = initAttempts <= 5 ? 1000 : initAttempts <= 15 ? 2000 : 3000;
      log(`API未就绪，${delay}ms 后重试...`);
      setTimeout(init, delay);
    } else {
      err('达到最大重试次数，以降级模式启动。缺少的API：');
      err('  SillyTavern:', !!ST, '  TavernHelper:', !!TH, '  jQuery:', !!$j);
      if (ST) err('  ST.callGenericPopup:', !!ST.callGenericPopup, '  ST.POPUP_TYPE:', !!ST.POPUP_TYPE);
      if (TH) err('  TH.getLorebookEntries:', !!TH.getLorebookEntries, '  TH.createLorebook:', !!TH.createLorebook);
      loadSettings();
      addMenuItem();
    }
  }

  // ─────────────────────────────────────────
  // 启动
  // ─────────────────────────────────────────
  const FLAG = `${SCRIPT_ID}_Loaded_v1_3_4`;
  if (typeof window[FLAG] === 'undefined') {
    window[FLAG] = true;

    const wjq = setInterval(() => {
      $j = typeof $ !== 'undefined' ? $ : (typeof jQuery !== 'undefined' ? jQuery : null);
      if ($j) {
        clearInterval(wjq);
        if (typeof toastr !== 'undefined') toastr_api = toastr;

        const state = document.readyState;
        const startDelay = state === 'complete' ? 1500 : 4000;
        log(`document.readyState=${state}，将在 ${startDelay}ms 后启动`);

        const go = () => setTimeout(init, startDelay);
        if (state === 'complete' || state === 'interactive') go();
        else document.addEventListener('DOMContentLoaded', go);
      }
    }, 100);
  } else {
    warn('Script already loaded, skipping.');
  }

})();
